# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify, render_template_string
import sqlite3
import string
import random

app = Flask(__name__)

# Simple in-memory database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users (email TEXT PRIMARY KEY, token TEXT)''')
    conn.commit()
    conn.close()

@app.route('/reset-password', methods=['POST'])
def reset_password():
    email = request.form.get('email')
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Generate a random token
    token = ''.join(random.choices(string.ascii_letters + string.digits, k=32))

    # Store the token in the database with the user's email
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    try:
        c.execute("INSERT INTO users (email, token) VALUES (?, ?)", (email, token))
    except sqlite3.IntegrityError:
        # Email already exists, update the token
        c.execute("UPDATE users SET token=? WHERE email=?", (token, email))
    finally:
        conn.commit()
        conn.close()

    # Send the reset link (for simplicity, just return it in the response)
    reset_link = f"http://yourdomain.com/reset?token={token}"
    return jsonify({'reset_link': reset_link})

if __name__ == '__main__':
    init_db()
    app.run(debug=True)